import{b as l,J as i,g as e,j as t}from"./chunks/framework.BFn5dPDD.js";const c=JSON.parse('{"title":"소개","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1779721638000}'),r={name:"index.md"};function o(n,a,h,s,d,p){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="소개" tabindex="-1">소개 <a class="header-anchor" href="#소개" aria-label="Permalink to &quot;소개&quot;">​</a></h1><p><strong>IBS Platform</strong>은 부동산 개발(시행) 프로젝트의 전 과정에서 발생하는 자금, 계약, 고객, 문서, 소송 등 핵심 데이터를 통합 관리하는 시스템입니다.</p><p>부동산 개발사업은 토지 확보에서 인허가, 분양, 수납, 자금 집행, 준공에 이르기까지 수많은 업무가 유기적으로 연결되어 있습니다. 각 단계에서 생성되는 데이터는 사업의 진행 상황을 보여주는 중요한 정보이자, 정확한 의사결정을 위한 기반이 됩니다.</p><p>IBS Platform은 이러한 데이터를 하나의 시스템에서 체계적으로 관리함으로써, 프로젝트 운영자가 반복적인 관리 업무에 소요되는 시간을 줄이고 사업의 본질적인 의사결정에 집중할 수 있도록 설계되었습니다.</p><h2 id="왜-ibs-platform인가" tabindex="-1">왜 IBS Platform인가? <a class="header-anchor" href="#왜-ibs-platform인가" aria-label="Permalink to &quot;왜 IBS Platform인가?&quot;">​</a></h2><p>부동산 개발사업은 공동주택, 주상복합, 오피스텔, 상업시설, 숙박시설 등 다양한 상품 유형과 복잡한 계약 구조를 포함합니다. 또한 일반분양, 조합사업, 임대사업 등 사업 방식에 따라 동일한 데이터라도 관리 방식과 프로세스가 달라집니다.</p><p>여기에 다음과 같은 업무가 동시에 진행됩니다.</p><ul><li>토지 매입 및 소유자별 계약 관리</li><li>프로젝트 자금 조달 및 집행</li><li>분양 계약 및 고객 관리</li><li>납부 일정 및 수납 관리</li><li>예산 대비 실적 분석</li><li>프로젝트 문서 및 법률 분쟁 관리</li></ul><p>이처럼 복잡한 업무를 엑셀이나 개별 시스템으로 관리하면 데이터의 일관성이 떨어지고, 중요한 정보를 적시에 파악하기 어려워집니다.</p><p>IBS Platform은 프로젝트 전반의 데이터를 통합하여 정확하고 일관된 정보를 제공함으로써, 운영자가 보다 신속하고 합리적인 판단을 내릴 수 있도록 지원합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><h3 id="프로젝트-기본-설정" tabindex="-1">프로젝트 기본 설정 <a class="header-anchor" href="#프로젝트-기본-설정" aria-label="Permalink to &quot;프로젝트 기본 설정&quot;">​</a></h3><ul><li>프로젝트 등록 및 유형별 상세 설정</li><li>계약 그룹, 유닛 타입, 동·호 구성 관리</li><li>납부 회차 및 계약 조건 설정</li><li>타입별·층별 공급가 관리</li></ul><h3 id="토지-매입-관리" tabindex="-1">토지 매입 관리 <a class="header-anchor" href="#토지-매입-관리" aria-label="Permalink to &quot;토지 매입 관리&quot;">​</a></h3><ul><li>사업 부지 및 소유자 목록 관리</li><li>토지 매입 계약 체결 및 진행 현황 관리</li></ul><h3 id="계약-및-고객-관리" tabindex="-1">계약 및 고객 관리 <a class="header-anchor" href="#계약-및-고객-관리" aria-label="Permalink to &quot;계약 및 고객 관리&quot;">​</a></h3><ul><li>계약 등록 및 고객 정보 관리</li><li>유닛과 계약의 1:1 매칭</li><li>계약 현황 및 통계 제공</li></ul><h3 id="수납-및-회계-관리" tabindex="-1">수납 및 회계 관리 <a class="header-anchor" href="#수납-및-회계-관리" aria-label="Permalink to &quot;수납 및 회계 관리&quot;">​</a></h3><ul><li>고객 납부금 수납 관리</li><li>일반 입출금 관리</li><li>고객 수납 데이터와 회계 자동 연동</li></ul><h3 id="예산-관리" tabindex="-1">예산 관리 <a class="header-anchor" href="#예산-관리" aria-label="Permalink to &quot;예산 관리&quot;">​</a></h3><ul><li>사업 예산 편성</li><li>예산 대비 집행 실적 분석</li><li>프로젝트 진행 단계별 자금 현황 파악</li></ul><h3 id="문서-및-소송-관리" tabindex="-1">문서 및 소송 관리 <a class="header-anchor" href="#문서-및-소송-관리" aria-label="Permalink to &quot;문서 및 소송 관리&quot;">​</a></h3><ul><li>본사 및 프로젝트 문서 관리</li><li>소송 및 법률 이슈 관리</li></ul><h2 id="ibs의-의미" tabindex="-1">IBS의 의미 <a class="header-anchor" href="#ibs의-의미" aria-label="Permalink to &quot;IBS의 의미&quot;">​</a></h2><p><strong>IBS</strong>는 <strong>I</strong>ntelligent <strong>B</strong>usiness <strong>S</strong>ystem의 약어입니다.</p><p>IBS는 단순한 업무 프로그램이 아니라, 부동산 개발사업 운영에 필요한 데이터를 체계적으로 축적하고 활용할 수 있도록 지원하는 플랫폼입니다.</p><p>프로젝트에서 발생하는 모든 핵심 정보를 하나의 시스템에 통합하여, 운영자는 필요한 정보를 언제든지 쉽게 조회하고 이를 바탕으로 더 나은 의사결정을 내릴 수 있습니다.</p><h2 id="우리의-지향점" tabindex="-1">우리의 지향점 <a class="header-anchor" href="#우리의-지향점" aria-label="Permalink to &quot;우리의 지향점&quot;">​</a></h2><p>부동산 개발은 단순히 건물을 짓는 일이 아니라, 사람이 살아가고 일하고 머무는 공간을 기획하고 실현하는 일입니다.</p><p>IBS Platform은 개발사업을 수행하는 디벨로퍼가 반복적인 관리 업무보다 더 중요한 일, 즉 시장을 이해하고 상품을 기획하며 더 나은 공간을 만드는 일에 집중할 수 있도록 돕는 운영 플랫폼이 되고자 합니다.</p><p>우리는 실제 프로젝트 수행 과정에서 얻은 경험을 바탕으로 IBS를 지속적으로 개선하며, 부동산 개발사업의 운영 표준을 만들어 가고 있습니다.</p><hr><p>프로그램 설치 및 기본 사용법은 <a href="/ibs/intro/getting-started.html">시작하기</a>에서 확인할 수 있습니다.</p>',33)])])}const m=l(r,[["render",o]]);export{c as __pageData,m as default};
